func messageContainerClass(role string) string {
	switch role {
	case "user":
		return "bg-muted/50 border border-border"
	case "assistant":
		return "bg-primary/5 border border-primary/20"
	case "system":
		return "bg-muted border border-border"
	case "tool":
		return "bg-muted/30 border border-border"
	default:
		return "bg-muted/50 border border-border"
	}
}

func countRoles(messages []memory.Message) map[string]int {
	counts := make(map[string]int)
	for _, msg := range messages {
		counts[msg.Role]++
	}
	return counts
}

